class Solution {
public:
void solve(vector<unordered_set<int>>& graph) {
  int max_component_size = 0;
  vector<bool> visited(graph.size(), false);
  vector<vector<int>> adj_list(graph.size());

  // Perform DFS for each unvisited node
  for (int i = 0; i < graph.size(); i++) {
    if (!visited[i]) {
      max_component_size = std::max(max_component_size, dfs(i, graph, visited, adj_list));
    }
  }

  return max_component_size;


int dfs(int node, vector<unordered_set<int>>& graph, vector<bool>& visited, vector<vector<int>>& adj_list) {
  visited[node] = true;
  adj_list[node].clear();

  for (int neighbor : graph[node]) {
    if (!visited[neighbor]) {
      dfs(neighbor, graph, visited, adj_list);
    }
  }
  return 1;
}
};
